) VALUES
    ('FRIT-F 461', 'CINÉMA ET CULTURE: LA FRANCE/LA FRANCOPHONIE CONTEMPORAINE', '13619', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'BH 333', 'Brett Bowles', 1, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Explores the links between cinema, culture, politics, and society in contemporary France and/or other parts of the French-speaking world, such as Africa and Québec.', ARRAY['COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('FRIT-F 499', 'READING FOR HONORS', '1812', 'Class Status', NULL, NULL, 'Hall Bjornstad', 12, NULL, 'Readings', '1–6', NULL, ARRAY[]::TEXT[], 'Independent reading and research in conjunction with an advanced honors paper or project. Does not count as F400-level course in residence for major.', ARRAY[]::TEXT[], NULL),
    ('FRIT-F 513', 'FRENCH RENAISSANCE PROSE', '30317', 'Closed', 'Th Thursday 4:00 PM–6:00 PM', 'BH 233', 'Eric MacPhail', 0, NULL, 'Seminar', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Prose works from sixteenth-century France including letters, essays, novels, short stories, Bible translations, travel accounts, political treatises, and philosophical dialogues by authors famous and obscure, humorous and solemn, terse and prolix. Also includes review of lexical and grammatical peculiarities of sixteenth-century French and typographic conventions of Renaissance printed books.', ARRAY[]::TEXT[], NULL),
    ('FRIT-F 545', 'ROMANS ET AUTRES RÉCITS DU 19E SIÈCLE', '33572', 'Class Status', 'Tu Tuesday 4:00 PM–6:00 PM', 'BH 106', 'Nicolas Valazza', 1, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Study of various forms of narrative (realist, fantastical, psychological, historical, decadent, etc.) in 19th century French literature.', ARRAY[]::TEXT[], NULL),
    ('FRIT-F 572', 'PRACTICUM IN COLLEGE FRENCH TEACHING', '1813', 'Class Status', 'Th Thursday 9:35 AM–10:50 AM', 'PV 270', 'Erin Candeias', 2, NULL, 'Practicum', '1', 'SPEA', ARRAY[]::TEXT[], 'Focused classroom observations followed by discussions; identification and evaluation of teaching techniques. Required of new associate instructors.', ARRAY[]::TEXT[], NULL),
    ('FRIT-F 576', 'INTRODUCTION TO FRENCH PHONOLOGY', '30309', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'BH 140', 'Jeffrey Lamontagne', 6, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Study of French phonology and the phonology/morphology interface within the framework of recent linguistic models, including solutions to major descriptive problems proposed from the early twentieth century to the present.', ARRAY[]::TEXT[], NULL),
    ('FRIT-F 580', 'APPLIED FRENCH LINGUISTICS', '30312', 'Class Status', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'BH 214', 'Kevin Rottet', 5, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Consideration of issues in the structure of French from a pedagogical perspective, with a particular focus on variation along social and geographical lines. Critical examination of the concept of the native speaker in applied linguistics and of the literature on immersion education.', ARRAY[]::TEXT[], NULL),
    ('FRIT-F 580', 'APPLIED FRENCH LINGUISTICS', '30396', 'Class Status', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'OL ONLINE', 'Kevin Rottet', 3, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Consideration of issues in the structure of French from a pedagogical perspective, with a particular focus on variation along social and geographical lines. Critical examination of the concept of the native speaker in applied linguistics and of the literature on immersion education.', ARRAY[]::TEXT[], NULL),
    ('FRIT-F 606', 'CAPSTONE PROJECT IN FRENCH TEACHING', '36934', 'Closed', NULL, NULL, 'Vincent Bouchard', 0, NULL, 'Independent Study', '3', NULL, ARRAY[]::TEXT[], 'Designed to be taken during the final semester of the MAT program to complete the student''s academic training and further their professional development. Students work with a faculty advisor on an extended research essay or a classroom project consisting of a pedagogical portfolio relevant to their work as teachers.', ARRAY[]::TEXT[], NULL),
    ('FRIT-F 679', 'FRENCH-BASED PIDGINS AND CREOLES', '30320', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'SY 200', 'Kevin Rottet', 0, NULL, 'Lecture', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'Study of the contact languages known as pidgins and creoles, focusing on those which are French-based. Topics include an overview of the history of the field; how the terms pidgin and creole are defined and used; theories of origin; the sociohistorical setting of creolization; stages of development; key linguistic structures.', ARRAY[]::TEXT[], NULL),
    ('FRIT-F 815', 'INDIVIDUAL READINGS IN FRENCH LITERATURE AND LINGUISTICS', '1814', 'Class Status', NULL, NULL, 'Hall Bjornstad', 12, NULL, 'Readings', '1–6', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('FRIT-F 825', 'SEMINAR IN FRENCH AND FRANCOPHONE STUDIES', '30315', 'Class Status', 'W Wednesday 4:00 PM–6:30 PM', 'BH 315', 'Vincent Bouchard', 4, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Intensive cross-historical and/or cross-disciplinary study of a topic in French and Francophone literature, cinema, media, or culture.', ARRAY[]::TEXT[], NULL),
    ('FRIT-F 875', 'RESEARCH IN FRENCH LITERATURE AND LANGUAGE', '1815', 'Class Status', NULL, NULL, 'Hall Bjornstad', 25, NULL, 'Research', '1–12', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('FRIT-F 875', 'RESEARCH IN FRENCH LITERATURE AND LANGUAGE', '3715', 'Class Status', NULL, NULL, 'Hall Bjornstad', 20, NULL, 'Research', '1–12', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('FRIT-G 901', 'ADVANCED RESEARCH', '1816', 'Class Status', NULL, NULL, 'Hall Bjornstad', 11, NULL, 'Research', '6', NULL, ARRAY[]::TEXT[], 'Available to graduate students who have completed all course requirements for their doctorates, have passed doctoral qualifying examinations, and have the requisite number of degree credit hours, this course provides the advanced research student with a forum for sharing ideas and problems under the supervision of a senior researcher.', ARRAY[]::TEXT[], NULL),
    ('FRIT-G 901', 'ADVANCED RESEARCH', '1817', 'Class Status', NULL, NULL, 'Hall Bjornstad', 9, NULL, 'Research', '6', NULL, ARRAY[]::TEXT[], 'Available to graduate students who have completed all course requirements for their doctorates, have passed doctoral qualifying examinations, and have the requisite number of degree credit hours, this course provides the advanced research student with a forum for sharing ideas and problems under the supervision of a senior researcher.', ARRAY[]::TEXT[], NULL),
    ('FRIT-M 100', 'ELEMENTARY ITALIAN I', '1819', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'GA 0009', 'Cristina D''Errico', 1, NULL, 'Drill', '4', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Introduction to contemporary Italian language, geography, and culture. Involves a broad variety of assignments and activities that develop grammatical competency and proficiency in listening, speaking, reading, and writing. Cultural topics and simple cultural comparison are introduced.', ARRAY['IUB GenEd World Language class'], NULL),
