    ('FRIT-M 100', 'ELEMENTARY ITALIAN I', '6231', 'Closed', 'Tu Tuesday 9:35 AM–10:50 AM', 'WB WEB', 'Natalia Pineda Nunez', 0, NULL, 'Drill', '4', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Introduction to contemporary Italian language, geography, and culture. Involves a broad variety of assignments and activities that develop grammatical competency and proficiency in listening, speaking, reading, and writing. Cultural topics and simple cultural comparison are introduced.', ARRAY['IUB GenEd World Language class'], NULL),
    ('FRIT-M 150', 'ELEMENTARY ITALIAN II', '1822', 'Class Status', 'MWF Monday, Wednesday, Friday 1:55 PM–2:45 PM', 'WI C109', 'Luis Pulcinella', 5, NULL, 'Drill', '4', 'WILLKIE C', ARRAY[]::TEXT[], 'Continued introduction to contemporary Italian language, geography, and culture. Involves a broad variety of assignments and activities that build grammatical competency and proficiency in listening, speaking, reading and writing. Practice with new cultural topics and basic cultural analysis.', ARRAY['IUB GenEd World Language class'], NULL),
    ('FRIT-M 150', 'ELEMENTARY ITALIAN II', '7595', 'Closed', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'BH 240', 'Natalia Pineda Nunez', 0, NULL, 'Drill', '4', 'WILLKIE C', ARRAY[]::TEXT[], 'Continued introduction to contemporary Italian language, geography, and culture. Involves a broad variety of assignments and activities that build grammatical competency and proficiency in listening, speaking, reading and writing. Practice with new cultural topics and basic cultural analysis.', ARRAY['IUB GenEd World Language class'], NULL),
    ('FRIT-M 200', 'INTERMEDIATE ITALIAN I', '1824', 'Class Status', 'MWF Monday, Wednesday, Friday 1:55 PM–2:45 PM', 'BH 141', 'Davide Salvo', 6, NULL, 'Drill', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Building on Elementary Italian I and II, students further study and practice fundamental concepts and structures in Italian grammar. Through a variety of assignments and activities, they strengthen proficiency in listening, speaking, reading, writing, cultural analysis and understanding. Includes an introduction to brief literary texts.', ARRAY['IUB GenEd World Language class'], NULL),
    ('FRIT-M 200', 'INTERMEDIATE ITALIAN I', '6895', 'Closed', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'GA 0011', 'Davide Salvo', 0, NULL, 'Drill', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Building on Elementary Italian I and II, students further study and practice fundamental concepts and structures in Italian grammar. Through a variety of assignments and activities, they strengthen proficiency in listening, speaking, reading, writing, cultural analysis and understanding. Includes an introduction to brief literary texts.', ARRAY['IUB GenEd World Language class'], NULL),
    ('FRIT-M 200', 'INTERMEDIATE ITALIAN I', '8860', 'Closed', 'MWF Monday, Wednesday, Friday 12:45 PM–1:35 PM', 'GA 0011', 'Davide Salvo', 0, NULL, 'Drill', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Building on Elementary Italian I and II, students further study and practice fundamental concepts and structures in Italian grammar. Through a variety of assignments and activities, they strengthen proficiency in listening, speaking, reading, writing, cultural analysis and understanding. Includes an introduction to brief literary texts.', ARRAY['IUB GenEd World Language class'], NULL),
    ('FRIT-M 203', 'CONVERSATIONAL PRACTICE WITH ITALIANS', '30378', 'Class Status', NULL, NULL, 'Karolina Serafin', 7, NULL, 'Discussion', '1', NULL, ARRAY[]::TEXT[], 'Gives intermediate students the opportunity to partner with Italian university students for conversation in Italian and English. Focuses on language practice and intercultural understanding.', ARRAY[]::TEXT[], NULL),
    ('FRIT-M 215', 'ACCELERATED SECOND-YEAR ITALIAN', '4294', 'Class Status', 'MTuWTh Monday, Tuesday, Wednesday, Thursday 9:10 AM–10:00 AM', 'BH 134', 'Karolina Serafin', 1, NULL, 'Drill', '4', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'An accelerated treatment of material covered in both FRIT-M 200 and FRIT-M 250. Designed for students who have completed FRIT-M 115 and other highly-motivated students, students with extensive experience with another language, and/or students who aspire to study abroad.', ARRAY['IUB GenEd World Language class'], NULL),
    ('FRIT-M 250', 'INTERMEDIATE ITALIAN II', '8743', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'BH 336', 'Holly Fizer', 10, NULL, 'Drill', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'The study of more complex concepts and structures in Italian grammar. Through a variety of texts, media, and assignments, students practice listening, speaking, reading, writing, and they analyze cultural topics and situations in greater depth. Increased attention to short literary texts.', ARRAY['IUB GenEd World Language class'], NULL),
    ('FRIT-M 250', 'INTERMEDIATE ITALIAN II', '9393', 'Closed', 'W Wednesday 9:35 AM–10:50 AM', 'WB WEB', 'Holly Fizer', 0, NULL, 'Drill', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'The study of more complex concepts and structures in Italian grammar. Through a variety of texts, media, and assignments, students practice listening, speaking, reading, writing, and they analyze cultural topics and situations in greater depth. Increased attention to short literary texts.', ARRAY['IUB GenEd World Language class'], NULL),
    ('FRIT-M 250', 'INTERMEDIATE ITALIAN II', '10150', 'Closed', 'W Wednesday 7:05 PM–8:20 PM', 'WB WEB', 'Holly Fizer', 0, NULL, 'Drill', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'The study of more complex concepts and structures in Italian grammar. Through a variety of texts, media, and assignments, students practice listening, speaking, reading, writing, and they analyze cultural topics and situations in greater depth. Increased attention to short literary texts.', ARRAY['IUB GenEd World Language class'], NULL),
    ('FRIT-M 300', 'VIEWING ITALY: CINEMA, TV, AND SOCIAL MEDIA', '12676', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'WI C109', 'Sonia Cani', 7, NULL, 'Lecture', '3', 'WILLKIE C', ARRAY[]::TEXT[], 'Conducted in Italian, this course continues the study of advanced language through contemporary Italian cinema. While the course focuses on developing speaking abilities, it integrates other language skills and extensive analysis of contemporary Italian culture through a wide variety of topics, such as LGBTQ rights, immigration, religion, politics, and others.', ARRAY[]::TEXT[], NULL),
    ('FRIT-M 322', 'VISIONS OF ITALY THROUGH THE ARTS, MEDIA, SOCIETY, AND CULTURE', '13622', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'BH 214', 'Cristina D''Errico', 12, NULL, 'Seminar', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Study of Italian culture and society through a variety of visual and textual materials. Develops advanced language skills in parallel with visual literacy skills through investigation of different representations of the conditions, questions, and ideals that have shaped Italy as a nation and as a global player over time.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('FRIT-M 450', 'SEMINAR IN ITALIAN LITERATURE', '30306', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'BH 315', 'Marco Arnaudo', 8, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'In-depth and discussion-rich analysis of specific movements, topics, or authors of Italian literature. Course content and focus vary according to time periods, genres, themes, and cultural questions. Taught in Italian.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('FRIT-M 499', 'READING FOR HONORS', '1826', 'Class Status', NULL, NULL, 'Hall Bjornstad', 5, NULL, 'Readings', '1–6', NULL, ARRAY[]::TEXT[], 'Independent reading and research under the guidance of a faculty member, culminating in an advanced honors paper or project.', ARRAY[]::TEXT[], NULL),
    ('FRIT-M 504', 'RENAISSANCE ITALIAN LITERATURE AND CULTURE', '30310', 'Class Status', 'Tu Tuesday 12:00 PM–2:00 PM', 'BH 233', 'Marco Arnaudo', 6, NULL, 'Lecture', '3–4', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Class may be taught as a survey course or may focus on any author, period, genre, or cultural theme from Petrarch to the late 1600s.', ARRAY[]::TEXT[], NULL),
    ('FRIT-M 572', 'ITALIAN TEACHING PRACTICUM', '4275', 'Class Status', 'Th Thursday 11:10 AM–12:25 PM', 'SE 009', 'Karolina Serafin', 7, NULL, 'Practicum', '1', 'SWAIN EAST', ARRAY[]::TEXT[], 'Instructors of Italian develop, practice, and evaluate the effectiveness of pedagogical approaches and materials. They create and discuss a variety of assessments for evaluating language skills and cultural knowledge.', ARRAY[]::TEXT[], NULL),
