    ('GER-G 100', 'BEGINNING GERMAN I', '30538', 'Closed', 'TuTh Tuesday, Thursday 9:10 AM–10:25 AM', 'BH 332', 'Daniel Mitropoulos', 0, NULL, 'Drill', '4', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Introduction to present-day German and to selected aspects of the cultures of German-speaking countries. Introduction to German grammatical forms and their functions. Development of listening comprehension, simple speaking proficiency, controlled reading skills and simple written compositions. Active oral participation required.', ARRAY['IUB GenEd World Language class'], NULL),
