    ('GER-G 150', 'BEGINNING GERMAN II', '1847', 'Class Status', 'MTuWTh Monday, Tuesday, Wednesday, Thursday 11:35 AM–12:25 PM', 'BH 246', 'Louise Bassini', 1, NULL, 'Drill', '4', 'SWAIN EAST', ARRAY[]::TEXT[], 'Introduction to present-day German and to selected aspects of the cultures of German-speaking countries. Introduction to German grammatical forms and their functions. Development of listening comprehension, simple speaking proficiency, controlled reading skills and simple written compositions. Active oral participation required.', ARRAY['IUB GenEd World Language class'], NULL),
    ('GER-G 150', 'BEGINNING GERMAN II', '1848', 'Class Status', 'MTuWTh Monday, Tuesday, Wednesday, Thursday 1:55 PM–2:45 PM', 'BH 133', 'Elaine Dalida', 12, NULL, 'Drill', '4', 'SWAIN EAST', ARRAY[]::TEXT[], 'Introduction to present-day German and to selected aspects of the cultures of German-speaking countries. Introduction to German grammatical forms and their functions. Development of listening comprehension, simple speaking proficiency, controlled reading skills and simple written compositions. Active oral participation required.', ARRAY['IUB GenEd World Language class'], NULL),
    ('GER-G 200', 'INTERMEDIATE GERMAN I', '30554', 'Class Status', 'MWF Monday, Wednesday, Friday 6:40 PM–7:30 PM', 'GA 0005', 'Lee Czerw', 10, NULL, 'Drill', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Further development of oral and written command of language structure. Review of selected grammatical items. Listening comprehension. Reading of literary and non-literary texts. Discussion of selected films. Oral presentations. Writing of compositions based on the material covered. Emphasis on both speaking proficiency and structural awareness. Conducted in German.', ARRAY['IUB GenEd World Language class'], NULL),
    ('GER-G 200', 'INTERMEDIATE GERMAN I', '1852', 'Class Status', 'MWTh Monday, Wednesday, Thursday 7:55 PM–8:45 PM', 'WB WEB', 'Lee Czerw', 4, NULL, 'Drill', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Further development of oral and written command of language structure. Review of selected grammatical items. Listening comprehension. Reading of literary and non-literary texts. Discussion of selected films. Oral presentations. Writing of compositions based on the material covered. Emphasis on both speaking proficiency and structural awareness. Conducted in German.', ARRAY['IUB GenEd World Language class'], NULL),
    ('GER-G 200', 'INTERMEDIATE GERMAN I', '1849', 'Closed', 'MWF Monday, Wednesday, Friday 9:10 AM–10:00 AM', 'GA 0007', 'Anna Spafford', 0, NULL, 'Drill', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Further development of oral and written command of language structure. Review of selected grammatical items. Listening comprehension. Reading of literary and non-literary texts. Discussion of selected films. Oral presentations. Writing of compositions based on the material covered. Emphasis on both speaking proficiency and structural awareness. Conducted in German.', ARRAY['IUB GenEd World Language class'], NULL),
    ('GER-G 200', 'INTERMEDIATE GERMAN I', '1850', 'Closed', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'SE 245', 'Olanrewaju Okuseinde', 0, NULL, 'Drill', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Further development of oral and written command of language structure. Review of selected grammatical items. Listening comprehension. Reading of literary and non-literary texts. Discussion of selected films. Oral presentations. Writing of compositions based on the material covered. Emphasis on both speaking proficiency and structural awareness. Conducted in German.', ARRAY['IUB GenEd World Language class'], NULL),
    ('GER-G 200', 'INTERMEDIATE GERMAN I', '1851', 'Closed', 'MWF Monday, Wednesday, Friday 12:45 PM–1:35 PM', 'BH 244', 'Olanrewaju Okuseinde', 0, NULL, 'Drill', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Further development of oral and written command of language structure. Review of selected grammatical items. Listening comprehension. Reading of literary and non-literary texts. Discussion of selected films. Oral presentations. Writing of compositions based on the material covered. Emphasis on both speaking proficiency and structural awareness. Conducted in German.', ARRAY['IUB GenEd World Language class'], NULL),
    ('GER-G 250', 'INTERMEDIATE GERMAN II', '1853', 'Closed', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'GA 0007', 'Lane Sorensen', 0, NULL, 'Drill', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Further development of oral and written command of language structures. Listening comprehension. Review of selected grammatical items. Discussion of modern German literary and non-literary texts, as well as films. Oral presentations. Writing of compositions based on the material covered. Emphasis on both speaking proficiency and structural awareness. Conducted in German.', ARRAY['IUB GenEd World Language class'], NULL),
    ('GER-G 250', 'INTERMEDIATE GERMAN II', '1854', 'Closed', 'MWF Monday, Wednesday, Friday 1:55 PM–2:45 PM', 'GA 0007', 'Lane Sorensen', 0, NULL, 'Drill', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Further development of oral and written command of language structures. Listening comprehension. Review of selected grammatical items. Discussion of modern German literary and non-literary texts, as well as films. Oral presentations. Writing of compositions based on the material covered. Emphasis on both speaking proficiency and structural awareness. Conducted in German.', ARRAY['IUB GenEd World Language class'], NULL),
    ('GER-G 300', 'FIFTH-SEMESTER COLLEGE GERMAN', '1855', 'Class Status', 'MWF Monday, Wednesday, Friday 12:45 PM–1:35 PM', 'SY 002', 'Nikole Langjahr', 8, NULL, 'Drill', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'Comprehensive review of grammatical points introduced in G100 through G250. Reading proficiency, systematic vocabulary building, composition, and discussion through the assignment of short literary texts and one novel or play. Conducted in German.', ARRAY[]::TEXT[], NULL),
    ('GER-G 305', 'INTRODUCTION TO GERMAN LITERATURE: TYPES', '12265', 'Class Status', 'MWF Monday, Wednesday, Friday 10:25 AM–11:15 AM', 'GA 0007', 'Lane Sorensen', 11, NULL, 'Drill', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Course Description Study of literary types (narrative, dramatic, lyric) with examples of each selected from two or more periods. Conducted in German.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('GER-G 330', 'SIXTH-SEMESTER COLLEGE GERMAN', '1856', 'Class Status', 'MWF Monday, Wednesday, Friday 1:55 PM–2:45 PM', 'GA 0013', 'Janine Emerson', 10, NULL, 'Drill', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Advanced oral and written communication. Study of selected advanced grammatical topics. Reading of primarily non-literary texts. Required for teacher certification. Conducted in German.', ARRAY[]::TEXT[], NULL),
    ('GER-G 332', 'INTRODUCTION TO GERMAN LITERATURE AND MEDIA', '30354', 'Class Status', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'SW 218', 'Michel Chaouli', 10, NULL, 'Lecture', '3', 'SWAIN WEST', ARRAY[]::TEXT[], 'Gateway course to the study of German literature and media. Provides the basic tools of the analysis of literature, film and media. Content varies and may focus on either literature or film/media. Conducted in German.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('GER-G 399', 'HONORS TUTORIAL', '1857', 'Class Status', NULL, NULL, 'Nikole Langjahr', 2, NULL, 'Independent Study', '1–2', NULL, ARRAY[]::TEXT[], 'Tutorial may be taken for 1 credit in conjunction with an upper-level course in which the student is concurrently enrolled, or independently for 2 credits under the supervision of a faculty member.', ARRAY[]::TEXT[], NULL),
    ('GER-G 415', 'PERSPECTIVES ON GERMAN LITERATURE', '30355', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'GA 0005', 'Benjamin Robinson', 5, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Study of one aspect of German literature: formal, historical, political, psychological, etc. Relation to wider concerns in and outside of literature. Topic announced in the online Schedule of Classes. Conducted in German.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('GER-G 458', 'INTRODUCTION TO GERMAN MORPHOLOGY', '30356', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'SY 200', 'Elliott Evans', 9, NULL, 'Lecture', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'In-depth study of the principles underlying word formation (morphology) in German. Comparative study of inflection, derivation, and compounding in German and English. Conducted in German.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('GER-G 464', 'GERMAN CULTURE AND SOCIETY', '13858', 'Class Status', 'MWF Monday, Wednesday, Friday 1:55 PM–2:45 PM', 'BH 233', 'Nikole Langjahr', 10, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'The interaction of social, intellectual, and artistic forces in German life of the past two centuries, with emphasis on important developments and figures. Conducted in German.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('GER-G 491', 'ELEM GERMAN FOR GRAD STUDENTS', '1858', 'Class Status', 'MW Monday, Wednesday 7:05 PM–8:20 PM', 'WB WEB', 'Brian Hensley', 2, NULL, 'Drill', '4', 'WEB-BASED CLASS', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('GER-G 491', 'ELEM GERMAN FOR GRAD STUDENTS', '1859', 'Class Status', 'MW Monday, Wednesday 7:05 PM–8:20 PM', 'WB WEB', 'Brian Hensley', 21, NULL, 'Drill', '4', 'WEB-BASED CLASS', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('GER-G 496', 'ADVANCED GERMAN LANGUAGE ABROAD', '1860', 'Class Status', NULL, NULL, 'Nikole Langjahr', 2, NULL, 'Independent Study', '1–6', NULL, ARRAY[]::TEXT[], 'Credit for advanced German language study in a German-speaking country when no specific equivalent is available among departmental offerings.', ARRAY[]::TEXT[], NULL),
