    ('GER-G 579', 'HISTORICAL STUDY OF GERMAN LITERATURE V', '30352', 'Class Status', 'Th Thursday 5:30 PM–7:45 PM', 'BH 015', 'Teresa Kovacs', 2, NULL, 'Seminar', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Historical treatment of a literary topic involving developments within the period from the late 20th century to the 21st-century present. Topics range from individual genres, types, or movements; to themes or ideas; to sociopolitical contexts of literature or its relationships to other art forms. May be repeated with different topic.', ARRAY[]::TEXT[], NULL),
    ('GER-G 599', 'THESIS RESEARCH', '3077', 'Class Status', NULL, NULL, 'Christopher Sapp', 1, NULL, 'Research', '0', NULL, ARRAY[]::TEXT[], 'Master''s students who have enrolled in 30 or more hours of graduate course work applicable to the degree and who have completed all other requirements of the degree except the thesis of final project of performance may enroll in G599. Requires section authorization.', ARRAY[]::TEXT[], NULL),
