    ('GER-K 100', 'BEGINNING NORWEGIAN I', '1868', 'Class Status', 'MTuWTh Monday, Tuesday, Wednesday, Thursday 11:35 AM–12:25 PM', 'BH 307', 'Elaine Dalida, Gergana May', 15, NULL, 'Drill', '4', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Development of listening comprehension, speaking, reading, and writing skills in a cultural context. Introduction to grammar.', ARRAY['IUB GenEd World Language class'], NULL),
