    ('GER-N 100', 'BEGINNING DUTCH I', '1870', 'Class Status', 'MTuWTh Monday, Tuesday, Wednesday, Thursday 11:35 AM–12:25 PM', 'BH 245', 'Cynthia Vaona, Frane Burazer', 1, NULL, 'Drill', '4', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Development of speaking ability, stress on pronunciation, leading to fluency on restricted topics. Introduction to grammar. Reading of annotated stories.', ARRAY['IUB GenEd World Language class'], NULL),
    ('GER-N 200', 'DUTCH READING, COMPOSITION, AND CONVERSATION I', '5527', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'BH 336', 'Frane Burazer', 8, NULL, 'Recitation', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Development of oral fluency, attention to idiom. Further grammatical study; attending to formal writing style. Readings in Dutch literature and culture.', ARRAY['IUB GenEd World Language class'], NULL),
    ('GER-N 401', 'INTENSIVE DUTCH I', '1871', 'Class Status', 'MTuWTh Monday, Tuesday, Wednesday, Thursday 11:35 AM–12:25 PM', 'BH 245', 'Cynthia Vaona, Frane Burazer', 1, NULL, 'Drill', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Designed to impart a fluency in both written and spoken Dutch and to prepare students for advanced work in Dutch literature and language.', ARRAY[]::TEXT[], NULL),
    ('GER-N 403', 'DUTCH READING, COMPREHENSION, AND CONVERSATION I', '5528', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'BH 336', 'Frane Burazer', 8, NULL, 'Recitation', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Further review and study of grammar at advanced level. Practice in controlling spoken and written styles. Frequent short compositions. Reading and discussion of several classics of Dutch literature. Language of instruction: Dutch.', ARRAY[]::TEXT[], NULL),
