    ('GER-T 540', 'GERMANY AND THE U.S.', '32431', 'Closed', NULL, 'OL ONLINE', 'Jeffrey Luppes', 0, NULL, 'Seminar', '3', 'Online Class', ARRAY[]::TEXT[], 'The course centers on the following key questions: How has Germany used America to define and understand itself? And, what does this say about the way Germans see themselves?', ARRAY[]::TEXT[], NULL),
