    ('GNDR-G 205', 'THEMES IN GENDER STUDIES', '29994', 'Closed', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'PY 109', 'Corey Tatz', 0, NULL, 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Exploration of a theme or series of themes arising from the study of gender, generally from within a particular discipline or subfield. Provides critical reflection upon the challenges of analyzing gender within the framework of different disciplines of knowledge.', ARRAY['IUB GenEd S&H credit
COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('GNDR-G 206', 'GAY HISTORIES, QUEER CULTURES', '12199', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'BH 143', 'Meredith Lee', 2, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Examines the social, cultural, and political history of same-sex relationships and desires in the United States and abroad, emphasizing the historical emergence of certain American sexual subcultures, such as the modern lesbian and gay "movement" or "community". The course also highlights particular formations such as race, class, and regional difference that interrupt unified, universal narratives of lesbian and gay history.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('GNDR-G 215', 'SEX AND GENDER IN CROSS CULTURAL PERSPECTIVE', '32287', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'LH 328', 'Lessie Frazier', 2, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], NULL, ARRAY['IUB GenEd S&H credit
COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('GNDR-G 225', 'GENDER SEXUALITY & POP CULTURE', '1878', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'FA 102', 'Gabriel Peoples', 6, NULL, 'Lecture', '3', 'FINE ARTS', ARRAY[]::TEXT[], NULL, ARRAY['IUB GenEd A&H credit
COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('GNDR-G 225', 'GENDER SEXUALITY & POP CULTURE', '10242', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'LH 102', 'Stephanie Allen', 1, NULL, 'Lecture', '3', 'FINE ARTS', ARRAY[]::TEXT[], NULL, ARRAY['IUB GenEd A&H credit
COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('GNDR-G 300', 'GENDER STUDIES: CORE CONCEPTS AND KEY DEBATES', '30020', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'LH 101', 'Gabriel Peoples', 4, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Examination of the field of gender studies. Students will explore a series of themes through which gender construction is discussed, analyzed, and defined. Conceptual frameworks of gender, theories of sexuality, and the cultural and historical construction of the body are emphasized. Examination of gender as a contested category ranging across categories of race, ethnicity, class, and nationality.', ARRAY['COLL INTENSIVE WRITING SECTIONS'], NULL),
    ('GNDR-G 302', 'ISSUES IN GENDER STUDIES', '13770', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'C2 203', 'Solimar Otero', 0, NULL, 'Lecture', '3', 'CLASSROOM-OFFICE BUILDING', ARRAY[]::TEXT[], 'This topical, variably-titled, seminar course addresses selected ideas, trends, and problems in the study of gender across academic disciplines. It explores a particular theme or themes and also provides critical reflection upon the challenges of analyzing gender within the framework of different disciplines of knowledge.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('GNDR-G 335', 'EXPLAINING SEX/GENDER DIFFERENCES', '12211', 'Class Status', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'BH 243', 'Jessica Hille', 11, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Explaining Sex/Gender Differences compares biological, psychological, and social theories regarding the development and maintenance of gender differentiated behavior, gender and sexual identities, and the meaning of sexed bodies. The course scrutinizes the social and cultural forces that magnify, minimize, or subvert the expression of gender differences.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('GNDR-G 350', 'QUEER THEORY', '30022', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'JH 001', 'Meredith Lee', 0, NULL, 'Lecture', '3', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'Examines queer theory, particularly in relation to other intellectual/political movements (post-structuralism, critical race studies, feminism, gay and lesbian studies) which it both borrowed from and challenged. Focus on the ways in which queer theory articulates a radical transformation of the sex/gender system in opposition to normalizing and essentializing impulses.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('GNDR-G 402', 'PROBLEMS IN GENDER STUDIES', '30023', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'LH 130', 'Brenda Weber', 30, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Topical seminar in gender studies. Analysis of a particular issue or problem that has generated debate within gender-related scholarship in a particular discipline, or across several disciplines/fields of inquiry.', ARRAY[]::TEXT[], NULL),
    ('GNDR-G 435', 'HEALTH, SEX AND GENDER', '12212', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'BH 144', 'Cynthia Graham', 1, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Examines health as it relates to female and male sexuality and to the roles and status of men and women in society. It explores public policy decisions related to medical research practices. Topics may include research about adult sexuality and personal health, contraception, sexual abuse, gender-specific diseases, and sexually transmitted diseases.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('GNDR-G 470', 'GENDER, RACE, SEXUALITY, AND THE LAW', '30025', 'Class Status', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'BH 144', 'Laura Foster', 16, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Examines the complex ways in which the law structures and is shaped by relations of gender, race, and sexuality. Introduces key legal cases and theory texts concerning reproductive rights, anti-sodomy laws, marriage, religion, free speech, affirmative action, and workplace discrimination.', ARRAY[]::TEXT[], NULL),
    ('GNDR-G 498', 'SEMINAR IN GENDER STUDIES', '30026', 'Class Status', 'Tu Tuesday 11:30 AM–2:00 PM', 'LH 201H', 'Stephanie Allen', 1, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('GNDR-G 499', 'SENIOR HONORS THESIS', '7517', 'Class Status', NULL, NULL, 'Jennifer Maher', 2, NULL, 'Independent Study', '3', NULL, ARRAY[]::TEXT[], 'Research and preparation of senior honors thesis.', ARRAY[]::TEXT[], NULL),
    ('GNDR-G 598', 'FEMINIST THEORY: CLASSIC TEXT AND FOUNDING DEBATES', '30027', 'Class Status', 'Tu Tuesday 11:30 AM–2:00 PM', 'LH 201H', 'Stephanie Allen', 2, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Explores founding texts of contemporary feminist theory, asking questions about identity, knowledge, sexuality, and ethics. Such works have emerged in relation to a variety of theoretical discourses, such as Marxism, structuralism, cultural studies, and others. Examines the intellectual history of feminist theory and its resonance with more recent trends.', ARRAY[]::TEXT[], NULL),
    ('GNDR-G 600', 'CONCEPTS OF GENDER', '5011', 'Class Status', 'Th Thursday 11:00 AM–1:30 PM', 'LH 201H', 'Judith Rodriguez', 2, NULL, 'Seminar', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Introduces historical, theoretical, behavioral, philosophical, scientific, multi- and cross-cultural perspectives on gender and its meanings. Attention is given to the emergence of the category "gender"; and applications to different fields of knowledge, experience, cultural expression, and institutional regulation, including queer, trans, and other theories of sex, sexuality, and desire.', ARRAY[]::TEXT[], NULL),
    ('GNDR-G 601', 'SCIENTIFIC PRACTICES AND FEMINIST KNOWLEDGE', '30028', 'Class Status', 'W Wednesday 9:00 AM–11:30 AM', 'LH 425', 'Laura Foster', 2, NULL, 'Seminar', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Examines intersections of gender and knowledge focusing on feminist analyses of scientific epistemology and practice, and the implications of feminist theories about the social meaning and gendered construction of scientific research. Particular focus is placed upon race, class, sexuality, and cultural difference in medical, psychological, and evolutionary accounts of "human nature."', ARRAY[]::TEXT[], NULL),
    ('GNDR-G 695', 'GRADUATE READINGS AND RESEARCH IN GENDER STUDIES', '4446', 'Class Status', NULL, NULL, 'Meredith Lee', 2, NULL, 'Readings', '1–6', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
