    ('GNDR-G 710', 'GENDER, MEDICINE AND THE BODY', '12215', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'BH 144', 'Cynthia Graham', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Examines topical themes related to medicine and the body as they interact with gender.', ARRAY[]::TEXT[], NULL),
