    ('GNDR-X 476', 'PRACTICUM IN GENDER STUDIES', '5019', 'Class Status', NULL, NULL, 'Jennifer Maher', 2, NULL, 'Practicum', '3–6', NULL, ARRAY[]::TEXT[], 'Directed study of issues or policies related to gender or sexuality based on a field experience. Directed readings, papers and/or an analytical journal may be required.', ARRAY[]::TEXT[], NULL),
