    ('GRAD-C 516', 'CYBERSECURITY CLINIC', '9888', 'Class Status', 'M Monday 4:45 PM–6:00 PM', 'WB WEB', 'Siddharth Bose, Scott Shackelford, Isak Nti Asare', 14, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'The IU Cybersecurity Clinic offers a service-learning opportunity for students to develop their understanding of cybersecurity risk management while working with clients across Indiana and beyond to improve their cybersecurity resilience. Students will learn cybersecurity best practices throughout the course and then help apply those lessons with their local clients.', ARRAY[]::TEXT[], NULL),
    ('GRAD-C 540', 'CYBERSECURITY INTERNSHIP', '12775', 'Class Status', NULL, NULL, 'Joelle Andrew-Mohr', 4, NULL, 'Internship', '0–3', NULL, ARRAY[]::TEXT[], 'Purpose of course is to allow cybersecurity graduate students opportunity to directly experience professional IT work environment. The internship provides opportunity to gain deeper understanding of principles discussed in the classroom as applied in real life situations. The internship may be taken for credit.', ARRAY[]::TEXT[], NULL),
    ('GRAD-C 590', 'TOPICS IN CYBERSECURITY RISK MANAGEMENT', '35214', 'Class Status', NULL, NULL, 'Joelle Andrew-Mohr', 10, NULL, 'Lecture', '1–3', NULL, ARRAY[]::TEXT[], 'Variable topics in cybersecurity risk management.', ARRAY[]::TEXT[], NULL),
    ('GRAD-C 590', 'TOPICS IN CYBERSECURITY RISK MANAGEMENT', '35215', 'Class Status', NULL, NULL, 'Joelle Andrew-Mohr', 8, NULL, 'Lecture', '1–3', NULL, ARRAY[]::TEXT[], 'Variable topics in cybersecurity risk management.', ARRAY[]::TEXT[], NULL),
    ('GRAD-G 514', 'FIELDWORK PRACTICUM IN HUMAN DIMENSIONS OF ENVIRONMENTAL CHANGE', '5198', 'Class Status', NULL, NULL, 'Tom Evans', 12, NULL, 'Lecture', '3', NULL, ARRAY[]::TEXT[], 'This practicum gives students the opportunity to practice research methods in an individually designed project in the Western Hemisphere. The project must address a specific issue in the study of institutions, populations and environmental change.', ARRAY[]::TEXT[], NULL),
    ('GRAD-G 597', 'IU GRADUATE EXCHANGE', '3751', 'Class Status', NULL, NULL, 'Margaret Key, Anna Bragin', 20, NULL, 'Independent Study', '0', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
