    ('GRAD-G 806', 'TRAILING STUDENTS', '6761', 'Class Status', NULL, NULL, 'Jared Lewis', 100, NULL, 'Colloquium', '0', NULL, ARRAY[]::TEXT[], 'A noncredit course for doctoral students, paid by outside funding, who follow newly hired faculty to IU from other universities for the purpose of completing research related to the non-IU degree. Use of this course requires approval by the University Graduate School.', ARRAY[]::TEXT[], NULL),
