    ('HHC-H 202', 'KNOWLEDGE PRODUCTION AND THE UNIVERSITY', '30493', 'Class Status', 'Th Thursday 12:45 PM–2:00 PM', 'HU 217', 'Sarah Frohardt-Lane', 1, NULL, 'Seminar', '1.5', 'HUTTON HONORS COLLEGE', ARRAY[]::TEXT[], 'Universities collect, preserve, and produce knowledge to address the universe of problems. Students in this PBL (Project-Based Learning) seminar explore one such contemporary problem and work in teams to address it. They conduct research across campus and present findings in public poster session or case competition.', ARRAY[]::TEXT[], NULL),
