    ('HHC-H 211', 'CLASSIC AUTHORS, CONTEMPORARY QUESTIONS I', '14652', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'HU 108', 'Richard Cecil', 0, NULL, 'Seminar', '3', 'HUTTON HONORS COLLEGE', ARRAY[]::TEXT[], 'How do remote works address current concerns? This course introduces major works of world literature (pre-1700) and encourages consideration of their relevance. Seminars take a thematic approach; readings may include works by Homer, Virgil, Sophocles, Augustine, Lady Murasaki, Dante, Christine de Pizan, Chaucer, Machiavelli, Cervantes, Montaigne, Galileo, Shakespeare, Descartes, others.', ARRAY['IUB GenEd A&H credit
COLL (CASE) A&H Breadth of Inquiry credit
COLL INTENSIVE WRITING SECTIONS'], NULL),
    ('HHC-H 211', 'CLASSIC AUTHORS, CONTEMPORARY QUESTIONS I', '14653', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'HU 111', 'Richard Cecil', 0, NULL, 'Seminar', '3', 'HUTTON HONORS COLLEGE', ARRAY[]::TEXT[], 'How do remote works address current concerns? This course introduces major works of world literature (pre-1700) and encourages consideration of their relevance. Seminars take a thematic approach; readings may include works by Homer, Virgil, Sophocles, Augustine, Lady Murasaki, Dante, Christine de Pizan, Chaucer, Machiavelli, Cervantes, Montaigne, Galileo, Shakespeare, Descartes, others.', ARRAY['IUB GenEd A&H credit
COLL (CASE) A&H Breadth of Inquiry credit
COLL INTENSIVE WRITING SECTIONS'], NULL),
    ('HHC-H 212', 'CLASSIC AUTHORS, CONTEMPORARY QUESTIONS II', '14655', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'HU 217', 'Norman Furniss', 12, NULL, 'Seminar', '3', 'HUTTON HONORS COLLEGE', ARRAY[]::TEXT[], 'How do works of social theory relate to the world? This course introduces major works of social-political thought (c. 1700-present) and encourages consideration of their relevance. Seminars take a thematic approach; readings from Smith, Rousseau, Burke, Wollstonecraft, Mill, Marx, Douglass, Nietzsche, Freud, Weber, DuBois, Arendt, Fanon, Rawls, and other writers.', ARRAY['IUB GenEd S&H credit
COLL (CASE) S&H Breadth of Inquiry credit
COLL INTENSIVE WRITING SECTIONS'], NULL),
    ('HHC-H 242', 'LEARNING FROM LIFE', '34213', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'HU 111', 'Robert Kunzman', 0, NULL, 'Seminar', '3', 'HUTTON HONORS COLLEGE', ARRAY[]::TEXT[], 'Multi- and interdisciplinary honors seminar focused on life experiences, lessons to take from them, and life-long learning in and outside of the classroom.', ARRAY[]::TEXT[], NULL),
