    ('HISP-P 311', 'ADVANCED GRAMMAR AND COMPOSITION IN PORTUGUESE', '6493', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'GY 1042', 'Luciana Namorato', 1, NULL, 'Discussion', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'An advanced course on basic grammar skills and composition. Emphasis on syntax, vocabulary usage, and writing.', ARRAY[]::TEXT[], NULL),
    ('HISP-P 400', 'LITERATURES OF THE PORTUGUESE - SPEAKING WORLD I', '29512', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'SE 009', 'Luciana Namorato', 0, NULL, 'Lecture', '3', 'SWAIN EAST', ARRAY[]::TEXT[], 'A general survey of the literature in Portuguese. The course emphasizes the unity and diversity of the literature in the major Portuguese-speaking areas of the world: Brazil, Portugal, and Luso Phone Africa. Starting with the parallel development of one literature (Portuguese) in distinct geographical areas (the Portuguese colonies), it will show the changes that take place when new nations are created in these areas, and new national literatures become a reality. the course will combine lecture and discussion, and will be conducted in Portuguese.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('HISP-P 415', 'WOMEN WRITING IN PORTUGUESE', '29518', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'BH 332', 'Estela Vieira', 7, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'A survey of women''s writings from different Portuguese-speaking nations.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
